import { request } from '../axios';
import { connectToApp } from '../common/connect-to-app';
import { getRedirectUri } from '../utils/url-utils';
import { isCookieSet, isRedirectedTo } from '../utils/workflow-utils';
import { authnSendPassword } from './authn-send-passord';
import { authnSendUsername } from './authn-send-username';
import { getOktaEnv } from './get-okta-env';
import { getOktaStateToken } from './get-okta-state-token';
import { stepUp } from './step-up';
import { validateToken } from './validate-token';
import log from 'loglevel';

export async function appOktaAuthenticationWorkflow(
  startUrl: string,
  username: string,
  password: string,
  response?: any,
) {
  log.info(`* Authenticating with '${username}' for '${startUrl}' using Okta`);

  let expectedCookie: string;

  // ----------------------------------------
  // Connect to application
  // ----------------------------------------

  // We may have already connected to the app to identify the type of IDP we are dealing with
  if (!response) response = await connectToApp(startUrl);

  expectedCookie = 'mod_auth_openidc_state_';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected application to set '${expectedCookie}' cookie.`);

  // Identify the Okta environnement and URLs
  const { oktaEnv, oktaAuthzURL } = getOktaEnv(response.headers.location);

  if (!isRedirectedTo(oktaAuthzURL, response))
    throw new Error(`Expected application to redirect to ${oktaAuthzURL}`);

  // Extract redirect_uri for later redirection check
  const redirect_uri = getRedirectUri(response.headers.location);

  // ----------------------------------------
  // Connect to Okta authz
  // ----------------------------------------

  const authzUrl: string = response.headers.location;
  response = await request({ method: 'GET', url: authzUrl });

  if (response.status != 200)
    throw new Error('Expected Okta login page to be successfully displayed.');

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response))
    console.log(`** Expected Okta authz to set '${expectedCookie}' cookie.`);

  // ----------------------------------------
  // Retrieve Okta stateToken
  // ----------------------------------------

  const stateToken = getOktaStateToken(response.data);
  console.log(`* stateToken = ${stateToken}`);

  // ----------------------------------------
  // Validate Okta stateToken
  // ----------------------------------------

  response = await validateToken(stateToken, oktaEnv);

  if (response.status != 200)
    throw new Error('Expected Okta introspect to be successful.');

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response))
    console.log(`** Token validation did not set '${expectedCookie}'.`);

  // ----------------------------------------
  // Send username to Okta
  // ----------------------------------------

  response = await authnSendUsername(username, stateToken, oktaEnv);

  if (response.status != 200)
    throw new Error('Expected username to be successfully sent to Okta.');

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response))
    console.log(`** Username validation did not set '${expectedCookie}'.`);

  // ----------------------------------------
  // Send password to Okta
  // ----------------------------------------

  response = await authnSendPassword(password, stateToken, oktaEnv);

  if (response.status != 200)
    throw new Error('Expected password to be successfully sent to Okta.');

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response))
    console.log(`** Password validation did not set '${expectedCookie}'.`);

  // ----------------------------------------
  // Ask Okta to redirect to the application
  // ----------------------------------------

  response = await stepUp(stateToken, oktaEnv);

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response))
    console.log(`** Step up did not set '${expectedCookie}' cookie.`);

  if (!isRedirectedTo(redirect_uri, response))
    throw new Error(`Expected Okta to redirect to ${redirect_uri}`);

  // ----------------------------------------
  // Open app oidc
  // ----------------------------------------

  response = await request({ method: 'GET', url: response.headers.location });

  expectedCookie = 'mod_auth_openidc_state_';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected app oidc to set '${expectedCookie}' cookie.`);

  expectedCookie = 'mod_auth_openidc_session';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected app oidc to set '${expectedCookie}' cookie.`);

  if (!isRedirectedTo(startUrl, response))
    throw new Error(`Expected app oidc to redirect to ${startUrl}`);
}
